import React, { useCallback, useRef, useState, useEffect } from "react";
import axios from "axios";
import JSZip from "jszip";
import { saveAs } from "file-saver";
import { Eye, FileUp, Scissors, Loader2, Trash2, Plus } from "lucide-react";
import { Document, Page, pdfjs } from "react-pdf";
import "react-pdf/dist/Page/AnnotationLayer.css";
import "react-pdf/dist/Page/TextLayer.css";

pdfjs.GlobalWorkerOptions.workerSrc = `//cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjs.version}/pdf.worker.min.js`;

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

const titleKeywords = [
  "HƯỚNG DẪN",
  "KẾ HOẠCH",
  "QUY ĐỊNH",
  "THÔNG BÁO",
  "NGHỊ QUYẾT",
  "CHỈ THỊ",
  "BÁO CÁO",
];

const detectDocNumber = (text) => {
  const value = (text || "").toUpperCase();
  const match = value.match(/SỐ\s*[:]?\s*\d{1,4}\s*[-–]\s*[A-Z0-9]{1,12}\/[A-Z0-9.\-]{1,12}/i);
  return match ? match[0].replace(/\s+/g, " ").trim() : "";
};

const suggestNameFromPage = (page) => {
  const preview = (page?.text_preview || "").trim();
  if (!preview) return "Van ban moi";

  const upper = preview.toUpperCase();
  const keyword = titleKeywords.find((k) => upper.includes(k));
  const docNo = detectDocNumber(preview);

  if (keyword && docNo) return `${keyword} ${docNo}`;
  if (keyword) return keyword;
  if (docNo) return `Van ban ${docNo}`;

  return preview.split(" ").slice(0, 7).join(" ");
};

const normalizeSplitPoints = (points, totalPages) => {
  const valid = (points || [])
    .map((p) => Number(p))
    .filter((p) => Number.isInteger(p) && p >= 0 && p < totalPages);

  const uniqueSorted = [...new Set(valid)].sort((a, b) => a - b);
  if (uniqueSorted.length === 0 || uniqueSorted[0] !== 0) {
    uniqueSorted.unshift(0);
  }
  return uniqueSorted;
};

function PreviewCellRenderer(props) {
  const handleClick = () => {
    props.context.onPreviewRange(props.data);
  };

  return (
    <button
      type="button"
      onClick={handleClick}
      className="inline-flex items-center gap-1 rounded-md border border-slate-300 bg-white px-3 py-1 text-xs font-medium text-slate-700 hover:bg-slate-50"
    >
      <Eye size={14} />
      Preview
    </button>
  );
}

export default function DigitalizationGrid() {
  const fileInputRef = useRef(null);

  const [selectedFile, setSelectedFile] = useState(null);
  const [fileId, setFileId] = useState("");
  const [totalPages, setTotalPages] = useState(0);
  const [allPages, setAllPages] = useState([]);
  const [rowData, setRowData] = useState([]);

  const [previewOpen, setPreviewOpen] = useState(false);
  const [previewDoc, setPreviewDoc] = useState(null);

  const [loadingStage, setLoadingStage] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const isBusy = Boolean(loadingStage);

  const columnDefs = useMemo(
    () => [
      {
        headerName: "STT",
        field: "index",
        width: 90,
        sortable: false,
        editable: false,
      },
      {
        headerName: "Ten file goi y",
        field: "suggestedName",
        flex: 1,
        minWidth: 280,
        editable: true,
        cellEditor: "agTextCellEditor",
      },
      {
        headerName: "Trang bat dau",
        field: "startPage",
        width: 150,
        editable: false,
      },
      {
        headerName: "Trang ket thuc",
        field: "endPage",
        width: 150,
        editable: false,
      },
      {
        headerName: "Hanh dong",
        field: "action",
        width: 140,
        cellRenderer: PreviewCellRenderer,
        editable: false,
        sortable: false,
      },
    ],
    []
  );

  const defaultColDef = useMemo(
    () => ({
      resizable: true,
      sortable: true,
      filter: false,
    }),
    []
  );

  const buildGridRows = useCallback((splitPoints, pages, pagesCount) => {
    const normalized = normalizeSplitPoints(splitPoints, pagesCount);

    const rows = normalized.map((startPage, idx) => {
      const nextStart = normalized[idx + 1];
      const endPageZeroBase = Number.isInteger(nextStart) ? nextStart - 1 : pagesCount - 1;

      const firstPage = pages[startPage] || {};
      const suggestedName = suggestNameFromPage(firstPage);

      return {
        id: `${idx}-${startPage}`,
        index: idx + 1,
        suggestedName,
        startPage,
        endPage: endPageZeroBase,
      };
    });

    return rows;
  }, []);

  const uploadAndAnalyze = useCallback(
    async (file) => {
      setError("");
      setSuccess("");
      setSelectedFile(file);

      try {
        setLoadingStage("Dang upload PDF...");
        const formData = new FormData();
        formData.append("file", file);

        const uploadRes = await axios.post(`${API_BASE}/upload`, formData, {
          headers: { "Content-Type": "multipart/form-data" },
        });

        const uploadedFileId = uploadRes.data.file_id;
        const uploadedTotalPages = Number(uploadRes.data.total_pages || 0);

        setFileId(uploadedFileId);
        setTotalPages(uploadedTotalPages);

        setLoadingStage("AI dang OCR va phan tich diem ngat...");
        const analyzeRes = await axios.get(`${API_BASE}/analyze/${uploadedFileId}`);

        const pages = analyzeRes.data.pages || [];
        const splitPoints = analyzeRes.data.suggested_breaks || [0];
        const total = Number(analyzeRes.data.total_pages || uploadedTotalPages || 0);

        setAllPages(pages);
        setTotalPages(total);
        setRowData(buildGridRows(splitPoints, pages, total));
        setSuccess("Da phan tich xong. Ban co the sua ten va xem preview truoc khi tach.");
      } catch (e) {
        setError(e?.response?.data?.detail || e.message || "Khong the upload/analyze file.");
      } finally {
        setLoadingStage("");
      }
    },
    [buildGridRows]
  );

  const onDropFile = useCallback(
    async (event) => {
      event.preventDefault();
      if (isBusy) return;

      const dropped = event.dataTransfer?.files?.[0];
      if (!dropped) return;
      if (dropped.type !== "application/pdf") {
        setError("Chi ho tro file PDF.");
        return;
      }

      await uploadAndAnalyze(dropped);
    },
    [isBusy, uploadAndAnalyze]
  );

  const onInputChange = useCallback(
    async (event) => {
      const file = event.target.files?.[0];
      if (!file) return;
      if (file.type !== "application/pdf") {
        setError("Chi ho tro file PDF.");
        return;
      }
      await uploadAndAnalyze(file);
    },
    [uploadAndAnalyze]
  );

  const buildSplitConfig = useCallback(() => {
    const starts = rowData
      .map((row) => Number(row.startPage))
      .filter((n) => Number.isInteger(n))
      .sort((a, b) => a - b);

    const breakPoints = normalizeSplitPoints(starts, totalPages);

    const documents = breakPoints.map((start, idx) => {
      const nextStart = breakPoints[idx + 1];
      const end = Number.isInteger(nextStart) ? nextStart - 1 : totalPages - 1;
      const gridRow = rowData.find((r) => r.startPage === start);

      return {
        order: idx + 1,
        name: gridRow?.suggestedName?.trim() || `van-ban-${idx + 1}`,
        start_page: start,
        end_page: end,
      };
    });

    return { breakPoints, documents };
  }, [rowData, totalPages]);

  const downloadZipFromBackendOrBuildClientZip = useCallback(
    async (splitResponse, currentFileId) => {
      if (splitResponse?.zip_url) {
        const zipBlobRes = await axios.get(`${API_BASE}${splitResponse.zip_url}`, {
          responseType: "blob",
        });
        saveAs(zipBlobRes.data, `${currentFileId}.zip`);
        return;
      }

      const files = splitResponse?.output_files || [];
      if (!files.length) {
        throw new Error("Khong nhan duoc danh sach file sau khi tach.");
      }

      const zip = new JSZip();

      await Promise.all(
        files.map(async (name) => {
          const fileRes = await axios.get(
            `${API_BASE}/download/${currentFileId}/${encodeURIComponent(name)}`,
            { responseType: "blob" }
          );
          zip.file(name, fileRes.data);
        })
      );

      const zipBlob = await zip.generateAsync({ type: "blob" });
      saveAs(zipBlob, `${currentFileId}.zip`);
    },
    []
  );

  const handleSplitAndDownload = useCallback(async () => {
    if (!fileId || rowData.length === 0) {
      setError("Chua co du lieu de tach.");
      return;
    }

    setError("");
    setSuccess("");

    try {
      const { breakPoints, documents } = buildSplitConfig();

      setLoadingStage("Dang yeu cau backend tach file...");
      const splitRes = await axios.post(`${API_BASE}/split`, {
        file_id: fileId,
        break_points: breakPoints,
        documents,
      });

      setLoadingStage("Dang dong goi va tai .zip...");
      await downloadZipFromBackendOrBuildClientZip(splitRes.data, fileId);

      setSuccess("Da tach va tai ve thanh cong file .zip.");
    } catch (e) {
      setError(e?.response?.data?.detail || e.message || "Khong the tach/tai file.");
    } finally {
      setLoadingStage("");
    }
  }, [buildSplitConfig, downloadZipFromBackendOrBuildClientZip, fileId, rowData.length]);

  const openPreview = useCallback(
    (row) => {
      const start = Number(row.startPage);
      const end = Number(row.endPage);

      setPreviewDoc({
        name: row.suggestedName,
        startPage: start,
        endPage: end,
      });
      setPreviewOpen(true);
    },
    []
  );

  const handleRowMouseOver = useCallback(
    (event) => {
      if (event.data) {
        openPreview(event.data);
      }
    },
    [openPreview]
  );

  return (
    <div className="mx-auto w-full max-w-7xl space-y-6 p-6">
      <div className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
        <div className="mb-4 flex items-start justify-between gap-4">
          <div>
            <h2 className="text-2xl font-semibold text-slate-800">So hoa va tach van ban PDF</h2>
            <p className="mt-1 text-sm text-slate-500">
              Upload PDF scan, AI se de xuat diem ngat, ban co the chinh sua ten truoc khi tach.
            </p>
          </div>
          {selectedFile && (
            <span className="rounded-full bg-slate-100 px-3 py-1 text-xs font-medium text-slate-700">
              File: {selectedFile.name}
            </span>
          )}
        </div>

        <div
          onDrop={onDropFile}
          onDragOver={(e) => e.preventDefault()}
          onClick={() => !isBusy && fileInputRef.current?.click()}
          className={`flex cursor-pointer flex-col items-center justify-center rounded-xl border-2 border-dashed p-10 text-center transition ${
            isBusy
              ? "border-slate-200 bg-slate-50"
              : "border-sky-300 bg-sky-50/50 hover:border-sky-400 hover:bg-sky-50"
          }`}
        >
          <input
            ref={fileInputRef}
            type="file"
            accept="application/pdf"
            className="hidden"
            onChange={onInputChange}
          />

          <FileUp className="mb-3 h-8 w-8 text-sky-600" />
          <p className="text-sm font-medium text-slate-700">
            Keo-tha file PDF vao day hoac bam de chon file
          </p>
          <p className="mt-1 text-xs text-slate-500">Chi ho tro dinh dang .pdf</p>
        </div>

        {loadingStage && (
          <div className="mt-4 flex items-center gap-2 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-sm text-amber-800">
            <Loader2 className="h-4 w-4 animate-spin" />
            {loadingStage}
          </div>
        )}

        {error && (
          <div className="mt-4 rounded-lg border border-rose-200 bg-rose-50 px-3 py-2 text-sm text-rose-700">
            {error}
          </div>
        )}

        {success && (
          <div className="mt-4 rounded-lg border border-emerald-200 bg-emerald-50 px-3 py-2 text-sm text-emerald-700">
            {success}
          </div>
        )}
      </div>

      <div className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm">
        <div className="mb-3 flex items-center justify-between">
          <div>
            <h3 className="text-lg font-semibold text-slate-800">Danh sach van ban con (AI de xuat)</h3>
            <p className="text-xs text-slate-500">
              Tong so trang: {totalPages} | So van ban de xuat: {rowData.length}
            </p>
          </div>
        </div>

        <div className="ag-theme-quartz h-[420px] w-full">
          <AgGridReact
            rowData={rowData}
            columnDefs={columnDefs}
            defaultColDef={defaultColDef}
            suppressRowClickSelection
            stopEditingWhenCellsLoseFocus
            context={{ onPreviewRange: openPreview }}
            onRowMouseOver={handleRowMouseOver}
            onCellValueChanged={(params) => {
              setRowData((prev) =>
                prev.map((row) => (row.id === params.data.id ? { ...row, ...params.data } : row))
              );
            }}
          />
        </div>

        <div className="mt-4 flex items-center justify-end">
          <button
            type="button"
            onClick={handleSplitAndDownload}
            disabled={isBusy || rowData.length === 0}
            className="inline-flex items-center gap-2 rounded-lg bg-indigo-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-indigo-700 disabled:cursor-not-allowed disabled:bg-slate-300"
          >
            {isBusy ? <Loader2 className="h-4 w-4 animate-spin" /> : <Scissors className="h-4 w-4" />}
            Bat dau tach va Tai ve (.zip)
          </button>
        </div>
      </div>

      {previewOpen && previewDoc && (
        <PdfPreviewModal
          fileUrl={`${API_BASE}/file/${fileId}`}
          startPage={previewDoc.startPage}
          endPage={previewDoc.endPage}
          onClose={() => setPreviewOpen(false)}
        />
      )}
    </div>
  );
}
